<script setup>
import { computed,onMounted,reactive,ref } from 'vue';import AppIcon from '../components/AppIcon.vue';import {get,post} from '../services/http';
const PERIODS=[['monthly','月付'],['quarterly','季付'],['half_yearly','半年付'],['yearly','年付'],['two_yearly','两年付'],['three_yearly','三年付'],['onetime','一次性'],['reset_traffic','重置流量']];
const RESET_METHODS=[['','跟随系统设置'],[0,'每月 1 号'],[1,'按订阅周期每月'],[2,'不重置'],[3,'每年 1 月 1 日'],[4,'按订阅周期每年']];
const plans=ref([]),groups=ref([]),loading=ref(true),saving=ref(false),busyId=ref(null),keyword=ref(''),statusFilter=ref('all'),groupFilter=ref(''),sorting=ref(false),sortDirty=ref(false),showForm=ref(false),tagInput=ref('');
const form=reactive(defaultForm()),toast=reactive({text:'',type:'success'});
function defaultForm(){return{id:null,name:'',content:'',group_id:null,transfer_enable:100,speed_limit:0,device_limit:0,capacity_limit:0,reset_traffic_method:null,transfer_price:null,prices:{},tags:[],show:true,sell:true,renew:true,force_update:false};}
const filtered=computed(()=>plans.value.filter(p=>{const term=keyword.value.trim().toLowerCase();return(!term||`${p.name} ${(p.tags||[]).join(' ')}`.toLowerCase().includes(term))&&(!groupFilter.value||Number(p.group_id)===Number(groupFilter.value))&&(statusFilter.value==='all'||(statusFilter.value==='selling'?p.show&&p.sell:statusFilter.value==='hidden'?!p.show:!p.sell));}));const displayed=computed(()=>sorting.value?plans.value:filtered.value);
const stats=computed(()=>({total:plans.value.length,selling:plans.value.filter(p=>p.show&&p.sell).length,users:plans.value.reduce((s,p)=>s+Number(p.users_count||0),0),active:plans.value.reduce((s,p)=>s+Number(p.active_users_count||0),0)}));
function notify(text,type='success'){toast.text=text;toast.type=type;window.clearTimeout(notify.timer);notify.timer=window.setTimeout(()=>toast.text='',2800);}
async function load(){loading.value=true;try{const [planData,groupData]=await Promise.all([get('/plan/fetch'),get('/server/group/fetch')]);plans.value=Array.isArray(planData)?planData:[];groups.value=Array.isArray(groupData)?groupData:[];}catch(e){notify(e.message,'error');}finally{loading.value=false;}}
function createPlan(source=null){const copy=source&&source.id?source:null;Object.assign(form,defaultForm(),copy?{...copy,id:null,name:`${copy.name} - 副本`,prices:{...(copy.prices||{})},tags:[...(copy.tags||[])],force_update:false}:{});tagInput.value='';showForm.value=true;}
function editPlan(p){Object.assign(form,defaultForm(),p,{prices:{...(p.prices||{})},tags:[...(p.tags||[])],force_update:false});tagInput.value='';showForm.value=true;}
function closeForm(force=false){if(!force&&!window.confirm('确定关闭？尚未保存的套餐配置将会丢失。'))return;showForm.value=false;Object.assign(form,defaultForm());}
function addTag(){const value=tagInput.value.trim();if(value&&!form.tags.includes(value))form.tags.push(value);tagInput.value='';}function removeTag(tag){form.tags=form.tags.filter(v=>v!==tag);}
async function save(){const validPrices=Object.fromEntries(Object.entries(form.prices).filter(([,v])=>v!==''&&v!=null&&Number(v)>0));if(!form.name.trim())return notify('请输入套餐名称','error');if(Number(form.transfer_enable)<1)return notify('流量配额必须大于 0 GB','error');if([form.speed_limit,form.device_limit,form.capacity_limit].some(v=>Number(v)<0))return notify('限制数值不能小于 0','error');if(!Object.keys(validPrices).length)return notify('请至少设置一个大于 0 的周期价格','error');if(form.force_update&&!window.confirm('强制同步会立即覆盖该套餐所有用户的权限组、流量、限速和设备数，确定继续？'))return;const before=new Set(plans.value.map(p=>p.id));saving.value=true;try{const payload={...form,group_id:form.group_id||null,reset_traffic_method:form.reset_traffic_method===''?null:form.reset_traffic_method,transfer_price:form.transfer_price===''?null:form.transfer_price,prices:validPrices};await post('/plan/save',payload);await load();let id=form.id;if(!id)id=plans.value.filter(p=>!before.has(p.id)).sort((a,b)=>b.id-a.id)[0]?.id;if(id)await post('/plan/update',{id,show:Boolean(form.show),sell:Boolean(form.sell),renew:Boolean(form.renew)});notify(form.id?'套餐已更新':'套餐已创建');closeForm(true);await load();}catch(e){notify(e.message,'error');}finally{saving.value=false;}}
async function toggle(p,field){busyId.value=p.id;try{await post('/plan/update',{id:p.id,[field]:!p[field]});p[field]=!p[field];notify('套餐状态已更新');}catch(e){notify(e.message,'error');}finally{busyId.value=null;}}
async function remove(p){if(p.users_count)return notify('该套餐仍有关联用户，无法删除','error');if(!window.confirm(`确定删除套餐「${p.name}」？存在历史订单时后端仍会阻止删除。`))return;busyId.value=p.id;try{await post('/plan/drop',{id:p.id});notify('套餐已删除');await load();}catch(e){notify(e.message,'error');}finally{busyId.value=null;}}
function enterSorting(){sorting.value=!sorting.value;sortDirty.value=false;if(sorting.value){keyword.value='';statusFilter.value='all';groupFilter.value='';}}function move(i,d){const t=i+d;if(t<0||t>=plans.value.length)return;const n=[...plans.value];[n[i],n[t]]=[n[t],n[i]];plans.value=n;sortDirty.value=true;}async function saveSort(){saving.value=true;try{await post('/plan/sort',{ids:plans.value.map(p=>p.id)});sorting.value=false;sortDirty.value=false;notify('套餐排序已保存');}catch(e){notify(e.message,'error');}finally{saving.value=false;}}
function money(v){return v==null?'未设置':`¥ ${Number(v).toFixed(2)}`;}function capacity(p){return Number(p.capacity_limit||0)?Math.min(100,Math.round(Number(p.active_users_count||0)/Number(p.capacity_limit)*100)):0;}function resetLabel(v){return RESET_METHODS.find(([k])=>String(k)===String(v??''))?.[1]||'跟随系统设置';}function periodCount(p){return PERIODS.filter(([key])=>Number(p.prices?.[key])>0).length;}function monthlyEquivalent(key,value){const months={quarterly:3,half_yearly:6,yearly:12,two_yearly:24,three_yearly:36}[key],price=Number(value);return months&&Number.isFinite(price)&&price>0?`约 ¥${(price/months).toFixed(2)}/月`:'';}
onMounted(load);
</script>
<template><section class="page-stack"><div class="page-heading page-heading-row"><div><h1>套餐管理</h1><p>配置订阅价格、流量权益、权限组、销售状态和容量限制。</p></div><button class="btn btn-primary" @click="createPlan"><AppIcon name="Plus" :size="16"/>添加套餐</button></div>
<div class="stat-grid plan-stats"><article class="stat-card"><span>套餐总数</span><strong>{{stats.total}}</strong></article><article class="stat-card"><span>销售中</span><strong>{{stats.selling}}</strong></article><article class="stat-card"><span>累计用户</span><strong>{{stats.users}}</strong></article><article class="stat-card"><span>有效用户</span><strong>{{stats.active}}</strong></article></div>
<div class="plan-toolbar"><label class="filter-input"><span>搜索</span><input v-model="keyword" :disabled="sorting" placeholder="套餐名称或标签"/></label><label class="field compact-field"><span>权限组</span><select v-model="groupFilter" :disabled="sorting"><option value="">全部权限组</option><option v-for="g in groups" :key="g.id" :value="g.id">{{g.name}}</option></select></label><label class="field compact-field"><span>销售状态</span><select v-model="statusFilter" :disabled="sorting"><option value="all">全部状态</option><option value="selling">销售中</option><option value="hidden">已隐藏</option><option value="stopped">停止新购</option></select></label><button class="btn btn-ghost" @click="enterSorting">{{sorting?'退出排序':'调整排序'}}</button><button v-if="sorting" class="btn btn-primary" :disabled="!sortDirty||saving" @click="saveSort">保存排序</button><button v-else class="btn btn-ghost" :disabled="loading" @click="load">刷新</button></div>
<div v-if="loading" class="panel settings-loading">正在加载套餐…</div><div v-else-if="!displayed.length" class="panel settings-loading">暂无符合条件的套餐</div><div v-else class="plan-grid"><article v-for="(p,index) in displayed" :key="p.id" class="panel plan-card" :class="{'capacity-warning':capacity(p)>=90}"><div v-if="sorting" class="sort-controls"><button class="icon-button" title="上移" :disabled="index===0" @click="move(index,-1)"><AppIcon name="ArrowUp" :size="16"/></button><button class="icon-button" title="下移" :disabled="index===plans.length-1" @click="move(index,1)"><AppIcon name="ArrowDown" :size="16"/></button></div><div class="plan-head"><div><span class="plan-group">{{p.group?.name||'未绑定权限组'}}</span><h2>{{p.name}}</h2><small>#{{p.id}} · {{resetLabel(p.reset_traffic_method)}} · {{periodCount(p)}} 个价格周期</small></div><div class="plan-badges"><span class="status-pill" :class="{off:!p.show}">{{p.show?'已展示':'已隐藏'}}</span><span class="status-pill" :class="{off:!p.sell}">{{p.sell?'可新购':'停新购'}}</span><span class="status-pill" :class="{off:!p.renew}">{{p.renew?'可续费':'停续费'}}</span></div></div><p class="plan-content">{{p.content||'暂无套餐说明'}}</p><div v-if="p.tags?.length" class="tag-list"><span v-for="tag in p.tags" :key="tag">{{tag}}</span></div><div class="plan-rights"><span><small>流量</small><strong>{{p.transfer_enable}} GB</strong></span><span><small>限速</small><strong>{{p.speed_limit||'不限'}}{{p.speed_limit?' Mbps':''}}</strong></span><span><small>设备</small><strong>{{p.device_limit||'不限'}}</strong></span><span><small>有效用户</small><strong>{{p.active_users_count||0}} / {{p.capacity_limit||'∞'}}</strong></span></div><div v-if="p.capacity_limit" class="plan-capacity" :class="{warning:capacity(p)>=90}"><i><em :style="{width:`${capacity(p)}%`}"/></i><span>{{capacity(p)>=100?'容量已满':`容量 ${capacity(p)}%`}}</span></div><div class="plan-prices"><span v-for="period in PERIODS.filter(([key])=>p.prices?.[key])" :key="period[0]"><small>{{period[1]}}</small><strong>{{money(p.prices[period[0]])}}</strong><em v-if="monthlyEquivalent(period[0],p.prices[period[0]])">{{monthlyEquivalent(period[0],p.prices[period[0]])}}</em></span><div v-if="!periodCount(p)" class="plan-price-warning">未设置可购买价格，用户无法购买</div></div><div class="plan-actions"><button class="btn btn-ghost btn-sm" :disabled="busyId===p.id" @click="toggle(p,'show')">{{p.show?'隐藏':'展示'}}</button><button class="btn btn-ghost btn-sm" :disabled="busyId===p.id" @click="toggle(p,'sell')">{{p.sell?'停止新购':'允许新购'}}</button><button class="btn btn-ghost btn-sm" :disabled="busyId===p.id" @click="toggle(p,'renew')">{{p.renew?'停止续费':'允许续费'}}</button><button class="btn btn-ghost btn-sm" @click="createPlan(p)">复制</button><button class="btn btn-ghost btn-sm" @click="editPlan(p)">编辑</button><button class="btn btn-danger btn-sm" :title="p.users_count?'仍有关联用户，无法删除':''" :disabled="p.users_count||busyId===p.id" @click="remove(p)">删除</button></div></article></div>
<div v-if="showForm" class="modal-backdrop" @click.self="closeForm"><section class="modal-card plan-modal"><div class="panel-head"><div><h2>{{form.id?'编辑套餐':'添加套餐'}}</h2><p>带 * 为必填项；金额单位为元，流量单位为 GB。</p></div><button class="btn btn-ghost" @click="closeForm">关闭</button></div><div class="plan-form-tip"><AppIcon name="Info" :size="16"/><span>新套餐默认展示并允许购买；至少配置一个价格周期后才能保存。</span></div><div class="smart-form"><label class="field field-wide"><span>套餐名称 *</span><input v-model.trim="form.name" maxlength="100" placeholder="例如：标准年付套餐"/></label><label class="field"><span>权限组</span><select v-model="form.group_id"><option :value="null">不绑定</option><option v-for="g in groups" :key="g.id" :value="g.id">{{g.name}}</option></select></label><label class="field"><span>流量配额（GB） *</span><input v-model.number="form.transfer_enable" type="number" min="1"/></label><label class="field"><span>速度限制（Mbps）</span><input v-model.number="form.speed_limit" type="number" min="0"/><small>0 表示不限速</small></label><label class="field"><span>设备数量限制</span><input v-model.number="form.device_limit" type="number" min="0"/><small>0 表示不限制</small></label><label class="field"><span>容量限制</span><input v-model.number="form.capacity_limit" type="number" min="0"/><small>0 表示不限人数</small></label><label class="field"><span>流量重置方式</span><select v-model="form.reset_traffic_method"><option v-for="m in RESET_METHODS" :key="String(m[0])" :value="m[0]">{{m[1]}}</option></select></label><label class="field"><span>套餐转让费（分）</span><input v-model.number="form.transfer_price" type="number" min="0" placeholder="留空继承系统设置"/><small>100 分 = 1 元</small></label><label class="field"><span>用户端展示</span><ToggleSwitch v-model="form.show" :true-value="true" :false-value="false" on-label="已展示" off-label="已隐藏" /></label><label class="field"><span>允许新购</span><ToggleSwitch v-model="form.sell" :true-value="true" :false-value="false" on-label="允许购买" off-label="停止购买" /></label><label class="field"><span>允许续费</span><ToggleSwitch v-model="form.renew" :true-value="true" :false-value="false" on-label="允许续费" off-label="停止续费" /></label><label class="field field-wide"><span>套餐说明</span><textarea v-model="form.content" rows="5" maxlength="10000" placeholder="支持 Markdown，可填写套餐权益和购买说明"/></label><label class="field field-wide"><span>标签</span><div class="tag-editor"><div class="tag-list"><button v-for="tag in form.tags" :key="tag" type="button" @click="removeTag(tag)">{{tag}} ×</button></div><input v-model="tagInput" maxlength="30" placeholder="输入标签后按回车" @keydown.enter.prevent="addTag" @blur="addTag"/></div></label></div><h3 class="plan-form-title">周期价格（元） *</h3><div class="price-editor"><label v-for="period in PERIODS" :key="period[0]"><span>{{period[1]}}</span><input v-model.number="form.prices[period[0]]" type="number" min="0" step="0.01" placeholder="不提供则留空"/><small v-if="monthlyEquivalent(period[0],form.prices[period[0]])">{{monthlyEquivalent(period[0],form.prices[period[0]])}}</small></label></div><label v-if="form.id" class="force-update"><ToggleSwitch v-model="form.force_update" :true-value="true" :false-value="false" on-label="强制同步" off-label="不影响现有用户" /><span><strong>强制同步现有用户</strong><small>将权限组、流量配额、限速和设备数立即覆盖到该套餐全部用户。</small></span></label><div class="modal-actions"><button class="btn btn-ghost" :disabled="saving" @click="closeForm">取消</button><button class="btn btn-primary" :disabled="saving" @click="save">{{saving?'保存中…':'保存套餐'}}</button></div></section></div><div v-if="toast.text" class="toast" :class="{error:toast.type==='error'}">{{toast.text}}</div></section></template>
